/**
 * Template for Swagger/OpenAPI plugin generation
 */

export interface SwaggerTemplateOptions {
  title?: string;
  version?: string;
  description?: string;
  routePrefix?: string;
}

/**
 * Generate Swagger plugin file content
 */
export function generateSwaggerTemplate(options: SwaggerTemplateOptions): string {
  const {
    title = 'Flusk API',
    version = '0.1.0',
    description = 'LLM Cost Optimization Platform',
    routePrefix = '/docs',
  } = options;

  return `/**
 * @generated by @flusk/cli
 * Swagger Plugin — auto-generated API docs
 */

import fp from 'fastify-plugin';
import type { FastifyInstance } from 'fastify';

async function swaggerPluginImpl(fastify: FastifyInstance) {
  await fastify.register(import('@fastify/swagger'), {
    openapi: {
      info: {
        title: '${title}',
        version: '${version}',
        description: '${description}',
      },
      servers: [{ url: '/' }],
    },
  });

  await fastify.register(import('@fastify/swagger-ui'), {
    routePrefix: '${routePrefix}',
  });
}

export const plugin = fp(swaggerPluginImpl, {
  fastify: '5.x',
  name: 'flusk-swagger',
});
`;
}
